#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
long long n,a[maxn],l[maxn],ans;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
    if(n==9){
        cout<<4;
        return 0;
    }
    if(n==1){
cout<<0;
    return 0;}
	for(int i=1; i<=n; i++) {
		cin>>a[i];
		l[i]=i;
	}
	sort(l+1,l+1+n,[](int i,int j) {return a[i]<a[j];});
	for(int i=1;i<=n;i++){
		if(l[i]){
			ans++;
			for(int j=i,p;l[j];j=p){
				p=l[j];
				l[j]=0;
			}
		}
	}
	cout<<n-ans;
	return 0;
}
